const data = $getWorkflowStaticData("global");
data.gospel_library_ingestion_results = [];
data.gospel_library_ingestion_started_at = new Date().toISOString();

return $input.all();

const entrada = $("Procesar una URL por vez").item.json;
const respuesta = $json;

function obtenerHost(url) {
  const match = String(url || "").match(/^https:\/\/(?:www\.)?([^\/?#]+)/i);
  return match ? match[1].toLowerCase() : "";
}

function obtenerPath(url) {
  const match = String(url || "").match(/^https:\/\/(?:www\.)?[^\/?#]+([^?#]*)/i);
  return match ? match[1] || "/" : "";
}

function obtenerLang(url) {
  const match = String(url || "").match(/[?&]lang=([^&#]+)/i);
  return match ? decodeURIComponent(match[1]).toLowerCase() : "";
}

function omitido(razon, extra = {}) {
  return [{
    json: {
      ...entrada,
      status: "skipped",
      razon,
      ...extra
    }
  }];
}

const sourceUrl = String(entrada.source_url || "");
const host = obtenerHost(sourceUrl);
const path = obtenerPath(sourceUrl);
const lang = obtenerLang(sourceUrl);
const idiomaDeclarado = String(entrada.language || "").toLowerCase();
const idiomasNoEspanoles = new Set(["de", "deu", "en", "eng", "fr", "fra", "it", "ita", "por", "pt"]);
const hostsPermitidos = new Set(["churchofjesuschrist.org", "discursosud.com", "speeches.byu.edu"]);

if (!sourceUrl || !host) {
  return omitido("La URL de origen no es valida.");
}

if (!hostsPermitidos.has(host)) {
  return omitido("La fuente no esta autorizada para esta ingesta.");
}

if (idiomasNoEspanoles.has(idiomaDeclarado)) {
  return omitido("El idioma declarado no es espanol.");
}

if (idiomasNoEspanoles.has(lang)) {
  return omitido("La URL declara un idioma no espanol.");
}

if (host === "churchofjesuschrist.org" && lang !== "spa") {
  return omitido("La pagina oficial no declara lang=spa.");
}

if (host === "speeches.byu.edu" && !path.startsWith("/spa/")) {
  return omitido("BYU Speeches solo admite discursos bajo /spa/.");
}

const headers = respuesta.headers || {};
const contentType = String(headers["content-type"] || headers["Content-Type"] || respuesta.contentType || "").toLowerCase();
const httpStatus = Number(respuesta.statusCode || respuesta.status || 0);
const body =
  typeof respuesta.body === "string"
    ? respuesta.body
    : typeof respuesta.data === "string"
      ? respuesta.data
      : typeof respuesta === "string"
        ? respuesta
        : "";

if (httpStatus !== 200) {
  return omitido("La fuente no respondio HTTP 200.", {
    tipo_recurso: "desconocido",
    http_status: httpStatus || null
  });
}

const parecePdf = contentType.includes("application/pdf") || /\.pdf(?:$|[?#])/i.test(sourceUrl) || body.startsWith("%PDF-");
const pareceHtml = contentType.includes("text/html") || /<(?:html|body|main|article|h1|p)\b/i.test(body);
const pareceTexto = contentType.includes("text/plain") && body.trim().length > 0;

if (parecePdf) {
  return omitido("skipped_pdf_pending: la extraccion de PDF no esta habilitada en este workflow.", {
    tipo_recurso: "pdf",
    content_type: "application/pdf",
    http_status: httpStatus
  });
}

if (!pareceHtml && !pareceTexto) {
  return omitido("El recurso no parece HTML ni texto limpio.", {
    tipo_recurso: "desconocido",
    http_status: httpStatus
  });
}

return [{
  json: {
    ...entrada,
    status: "recurso_detectado",
    tipo_recurso: pareceTexto ? "text" : "html",
    content_type: pareceTexto ? "text/plain" : "text/html",
    raw_content: body,
    http_status: httpStatus
  }
}];

function decodeEntities(value) {
  const named = {
    amp: "&",
    apos: "'",
    gt: ">",
    ldquo: "\"",
    lsquo: "'",
    lt: "<",
    nbsp: " ",
    ndash: "-",
    mdash: "-",
    quot: "\"",
    rdquo: "\"",
    rsquo: "'"
  };
  return String(value || "")
    .replace(/&#(\d+);/g, (_, code) => String.fromCodePoint(Number(code)))
    .replace(/&#x([0-9a-f]+);/gi, (_, code) => String.fromCodePoint(parseInt(code, 16)))
    .replace(/&([a-z]+);/gi, (match, name) => named[name.toLowerCase()] || match);
}

function normalizarTexto(value, conservarSaltos = false) {
  let texto = decodeEntities(value)
    .replace(/\u00a0/g, " ")
    .replace(/\u200b/g, "")
    .replace(/Ã‚/g, "")
    .replace(/ÃƒÂ±/g, "n")
    .replace(/Ã±/g, "n")
    .replace(/Ã¡/g, "a")
    .replace(/Ã©/g, "e")
    .replace(/Ã­/g, "i")
    .replace(/Ã³/g, "o")
    .replace(/Ãº/g, "u")
    .replace(/Ã¼/g, "u")
    .replace(/Ã¢â‚¬Å“|Ã¢â‚¬Â|â€œ|â€/g, "\"")
    .replace(/Ã¢â‚¬â„¢|â€™/g, "'")
    .normalize("NFC");
  if (conservarSaltos) {
    return texto
      .split(/\r?\n/)
      .map((linea) => linea.replace(/[^\S\n]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }
  return texto.replace(/\s+/g, " ").trim();
}

function firstMatch(html, patterns) {
  for (const pattern of patterns) {
    const match = html.match(pattern);
    if (match && match[1]) return normalizarTexto(match[1].replace(/<[^>]+>/g, " "));
  }
  return null;
}

function absoluteCanonical(href, fallback) {
  const value = decodeEntities(href).trim();
  if (/^https:\/\//i.test(value)) return value;
  if (value.startsWith("/")) {
    const host = String(fallback || "").match(/^(https:\/\/[^\/?#]+)/i);
    return host ? host[1] + value : fallback;
  }
  return fallback;
}

function canonicalFrom(html, fallback) {
  const links = html.match(/<link\b[^>]*>/gi) || [];
  for (const link of links) {
    if (!/\brel\s*=\s*["'][^"']*canonical/i.test(link)) continue;
    const href = link.match(/\bhref\s*=\s*["']([^"']+)["']/i);
    if (href && href[1]) return absoluteCanonical(href[1], fallback);
  }
  return fallback;
}

function authorFrom(html) {
  const metaTags = html.match(/<meta\b[^>]*>/gi) || [];
  for (const tag of metaTags) {
    if (!/\b(?:name|property)\s*=\s*["'](?:author|article:author|citation_author)["']/i.test(tag)) continue;
    const content = tag.match(/\bcontent\s*=\s*["']([^"']+)["']/i);
    if (content && content[1]) {
      const candidate = decodeEntities(content[1]).replace(/^por\s+/i, "").trim();
      if (!/(anonimo|desconocido|comentario)/i.test(candidate)) return candidate;
    }
  }
  const candidate = firstMatch(html, [
    /<(?:strong|b)[^>]*>\s*(?:por el|por la|por)\s+([^<]{3,120})<\/(?:strong|b)>/i,
    /<(?:p|div|span)[^>]+class=["'][^"']*(?:byline|speaker)[^"']*["'][^>]*>([\s\S]*?)<\/(?:p|div|span)>/i
  ]);
  return candidate && !/(anonimo|desconocido|comentario)/i.test(candidate)
    ? candidate.replace(/^(?:por\s+)?(?:el|la)\s+/i, "").trim()
    : null;
}

const item = $json;
if (item.status === "skipped") {
  return [{ json: item }];
}

const raw = String(item.raw_content || "");
const title = firstMatch(raw, [
  /<h1\b[^>]*>([\s\S]*?)<\/h1>/i,
  /<title\b[^>]*>([\s\S]*?)<\/title>/i
]);
const author = authorFrom(raw);
const canonicalUrl = item.tipo_recurso === "html" ? canonicalFrom(raw, item.source_url) : item.source_url;

let contenido = "";
if (item.tipo_recurso === "text") {
  contenido = normalizarTexto(raw, true);
} else {
  const html = raw
    .replace(/<!--[\s\S]*?-->/g, " ")
    .replace(/<(script|style|nav|footer|header|aside|noscript|form|svg|button|iframe)\b[^>]*>[\s\S]*?<\/\1>/gi, " ");
  const principal =
    (html.match(/<article\b[^>]*>([\s\S]*?)<\/article>/i) || [])[1] ||
    (html.match(/<main\b[^>]*>([\s\S]*?)<\/main>/i) || [])[1] ||
    (html.match(/<body\b[^>]*>([\s\S]*?)<\/body>/i) || [])[1] ||
    html;
  const lineas = decodeEntities(
    principal
      .replace(/<(br|\/p|\/li|\/h[1-6]|\/blockquote|\/section|\/div)>/gi, "\n")
      .replace(/<[^>]+>/g, " ")
  )
    .split(/\n+/)
    .map((linea) => normalizarTexto(linea))
    .filter((linea) => linea.length >= 20);
  const vistas = new Set();
  const basura = /^(inicio|menu|buscar|compartir|descargar|siguiente|anterior|todos los derechos|privacy|cookies?)\b/i;
  contenido = lineas
    .filter((linea) => {
      const key = linea.toLowerCase();
      if (basura.test(linea) || vistas.has(key)) return false;
      vistas.add(key);
      return true;
    })
    .join("\n\n")
    .trim();
}

return [{
  json: {
    ...item,
    status: "contenido_extraido",
    title: normalizarTexto(title || item.title || ""),
    author: normalizarTexto(author || item.author || "") || null,
    source_name: normalizarTexto(item.source_name || ""),
    canonical_url: canonicalUrl,
    content: normalizarTexto(contenido, true),
    extracted_at: new Date().toISOString(),
    extractor_version: "n8n-html-regex-v2",
    raw_content: undefined
  }
}];

const item = $json;
if (item.status === "skipped") {
  return [{ json: item }];
}

function obtenerLang(url) {
  const match = String(url || "").match(/[?&]lang=([^&#]+)/i);
  return match ? decodeURIComponent(match[1]).toLowerCase() : "";
}

function skipped(razon) {
  return [{
    json: {
      ...item,
      status: "skipped",
      razon,
      content: undefined
    }
  }];
}

const texto = String(item.content || "").trim();
const titulo = String(item.title || "").trim();
const idioma = String(item.language || "es").trim().toLowerCase();
const sourceUrl = String(item.source_url || "");
const canonicalUrl = String(item.canonical_url || "");
const idiomasNoEspanoles = new Set(["de", "deu", "en", "eng", "fr", "fra", "it", "ita", "por", "pt"]);
const frasesProhibidas = [
  "[reemplazar antes de enviar]",
  "documento de prueba",
  "no es una cita oficial",
  "no reemplaza ninguna fuente doctrinal",
  "contenido de prueba",
  "placeholder"
];
const textoAuditable = (titulo + "\n" + texto + "\n" + String(item.summary || "")).toLowerCase();
const palabras = (texto.toLowerCase().match(/[a-záéíóúüñ]+/g) || []);
const marcadoresEs = new Set([
  "al", "como", "con", "cristo", "de", "del", "dios", "el", "en", "es",
  "evangelio", "jesucristo", "la", "las", "los", "para", "por", "que",
  "se", "su", "una", "y"
]);
const marcadoresEn = new Set([
  "and", "are", "christ", "for", "from", "god", "is", "jesus", "of", "that",
  "the", "this", "to", "was", "with", "you"
]);
const cuentaEs = palabras.filter((palabra) => marcadoresEs.has(palabra)).length;
const cuentaEn = palabras.filter((palabra) => marcadoresEn.has(palabra)).length;
const proporcionEs = palabras.length ? cuentaEs / palabras.length : 0;
const basuraNavegacion = (texto.match(/\b(inicio|menu|buscar|compartir|suscribete|cookies?|privacidad|siguiente|anterior)\b/gi) || []).length;

if (!/^https:\/\//i.test(sourceUrl)) {
  return skipped("La URL de origen no es valida.");
}

if (sourceUrl.toLowerCase().includes("prueba-n8n")) {
  return skipped("La URL corresponde a una prueba n8n.");
}

if (idioma && idioma !== "es" && idioma !== "spa") {
  return skipped("El idioma declarado no es espanol.");
}

if (idiomasNoEspanoles.has(obtenerLang(sourceUrl)) || idiomasNoEspanoles.has(obtenerLang(canonicalUrl))) {
  return skipped("La URL declara un idioma no espanol.");
}

if (frasesProhibidas.some((frase) => textoAuditable.includes(frase))) {
  return skipped("El documento contiene texto de prueba o placeholder.");
}

if (!titulo || titulo.length < 3) {
  return skipped("No se pudo extraer un titulo confiable.");
}

if (texto.length < 300) {
  return skipped("El texto limpio tiene menos de 300 caracteres.");
}

if (palabras.length < 60) {
  return skipped("El documento contiene muy pocas palabras utiles.");
}

if (cuentaEs < 8 || proporcionEs < 0.025 || cuentaEn > cuentaEs) {
  return skipped("La heuristica no pudo confirmar que el contenido este en espanol.");
}

if (basuraNavegacion > 12) {
  return skipped("El contenido parece contener navegacion o texto repetido.");
}

return [{
  json: {
    ...item,
    status: "ready",
    language: "es",
    content: texto,
    validacion: {
      caracteres: texto.length,
      palabras: palabras.length,
      marcadores_es: cuentaEs,
      marcadores_en: cuentaEn
    }
  }
}];

const item = $json;

function skipped(razon) {
  return [{
    json: {
      ...item,
      status: "skipped",
      razon
    }
  }];
}

if (item.status !== "ready") {
  return [{ json: item }];
}

function obtenerHost(url) {
  const match = String(url || "").match(/^https:\/\/(?:www\.)?([^\/?#]+)/i);
  return match ? match[1].toLowerCase() : "";
}

function obtenerPath(url) {
  const match = String(url || "").match(/^https:\/\/(?:www\.)?[^\/?#]+([^?#]*)/i);
  return match ? match[1] || "/" : "";
}

function obtenerLang(url) {
  const match = String(url || "").match(/[?&]lang=([^&#]+)/i);
  return match ? decodeURIComponent(match[1]).toLowerCase() : "";
}

function normalizarTexto(value, conservarSaltos = false) {
  const texto = String(value || "")
    .replace(/&nbsp;|&#160;/gi, " ")
    .replace(/\u00a0/g, " ")
    .replace(/\u200b/g, "")
    .normalize("NFC");
  return conservarSaltos
    ? texto.split(/\r?\n/).map((linea) => linea.replace(/[^\S\n]+/g, " ").trim()).filter(Boolean).join("\n").replace(/\n{3,}/g, "\n\n").trim()
    : texto.replace(/\s+/g, " ").trim();
}

function normalizarEtiqueta(tag) {
  const limpia = normalizarTexto(tag);
  const traducciones = {
    "atonement": "Expiacion",
    "book of mormon": "Libro de Mormon",
    "covenants": "Convenios",
    "faith": "Fe",
    "gospel": "Evangelio",
    "holy ghost": "Espiritu Santo",
    "jesus christ": "Jesucristo",
    "prayer": "Oracion",
    "repentance": "Arrepentimiento",
    "temple": "Templo"
  };
  return traducciones[limpia.toLowerCase()] || limpia;
}

const sourceUrl = String(item.source_url || "");
let canonicalUrl = String(item.canonical_url || sourceUrl);
const host = obtenerHost(sourceUrl);
const canonicalHost = obtenerHost(canonicalUrl);
const lang = obtenerLang(sourceUrl);
const canonicalLang = obtenerLang(canonicalUrl);
const path = obtenerPath(sourceUrl);
const idiomasNoEspanoles = new Set(["eng", "por", "fra", "ita", "deu"]);
const hostsPermitidos = new Set(["churchofjesuschrist.org", "discursosud.com", "speeches.byu.edu"]);

if (!sourceUrl || !host) {
  return skipped("La URL de origen no es valida.");
}

if (!hostsPermitidos.has(host)) {
  return skipped("La fuente no esta autorizada para esta ingesta.");
}

if (canonicalHost && !hostsPermitidos.has(canonicalHost)) {
  return skipped("La URL canonica no pertenece a una fuente autorizada.");
}

if (idiomasNoEspanoles.has(lang) || idiomasNoEspanoles.has(canonicalLang)) {
  return skipped("La URL declara un idioma no espanol.");
}

if (host === "churchofjesuschrist.org" && lang !== "spa") {
  return skipped("El sitio oficial de la Iglesia debe declarar lang=spa.");
}

if (canonicalHost === "churchofjesuschrist.org" && canonicalLang && canonicalLang !== "spa") {
  return skipped("La URL canonica oficial debe declarar lang=spa.");
}

if (canonicalHost === "churchofjesuschrist.org" && !canonicalLang) {
  canonicalUrl = sourceUrl;
}

if (host === "speeches.byu.edu" && !path.startsWith("/spa/")) {
  return skipped("BYU Speeches solo se acepta en espanol bajo /spa/.");
}

const fuentes = {
  "discursosud.com": "Discursos SUD",
  "speeches.byu.edu": "BYU Speeches Espanol",
  "churchofjesuschrist.org": "Sitio oficial de la Iglesia"
};

const etiquetasBase = {
  "discursosud.com": ["Discursos SUD", "Doctrina"],
  "speeches.byu.edu": ["BYU Speeches", "Devocional"],
  "churchofjesuschrist.org": ["Iglesia de Jesucristo", "Fuente oficial"]
};

const title = normalizarTexto(item.title);
const content = normalizarTexto(item.content, true);

if (!title || title.length < 3) {
  return skipped("No se pudo preparar un titulo confiable.");
}

if (!content || content.length < 300) {
  return skipped("El contenido limpio es insuficiente para enviar a la API.");
}

const tags = [
  ...new Set([...(item.tags || []), ...(etiquetasBase[host] || [])].map(normalizarEtiqueta).filter(Boolean))
];

return [{
  json: {
    status: "ready",
    title,
    author: normalizarTexto(item.author) || null,
    source_name: normalizarTexto(item.source_name || fuentes[host] || host),
    source_url: sourceUrl,
    canonical_url: canonicalUrl,
    language: "es",
    content_type: item.content_type || "text/html",
    published_at: item.published_at || null,
    content,
    summary: normalizarTexto(item.summary, true) || null,
    tags,
    metadata: {
      ingestion_mode: "n8n_curated_v1",
      is_seed: false,
      ingested_by: "n8n",
      storage_used: false,
      source_site: host,
      extracted_at: item.extracted_at || new Date().toISOString(),
      extractor_version: item.extractor_version || "n8n-html-regex-v2",
      original_content_type: item.content_type || null,
      http_status: item.http_status || null
    }
  }
}];

const preparado = $("Preparar payload para Gospel Library IA").item.json;
const respuesta = $json;

function parseBody(value) {
  if (value && typeof value.body === "object" && value.body !== null) return value.body;
  if (value && typeof value.body === "string") {
    try {
      return JSON.parse(value.body);
    } catch {
      return {};
    }
  }
  if (value && typeof value.data === "object" && value.data !== null) return value.data;
  if (value && typeof value.data === "string") {
    try {
      return JSON.parse(value.data);
    } catch {
      return {};
    }
  }
  return value && typeof value === "object" ? value : {};
}

function previewSeguro(value) {
  const texto = JSON.stringify(value || {});
  return texto.length > 500 ? texto.slice(0, 500) + "..." : texto;
}

function registrarResultado(resultado) {
  const data = $getWorkflowStaticData("global");
  if (!Array.isArray(data.gospel_library_ingestion_results)) {
    data.gospel_library_ingestion_results = [];
  }
  data.gospel_library_ingestion_results.push(resultado);
  return [{ json: resultado }];
}

const body = parseBody(respuesta);
const httpStatus = Number(respuesta.statusCode || respuesta.status || 200);
const apiStatus = String(body.status || "").trim();
const chunksCount = Number(body.chunks_count || body.chunks || 0);
const base = {
  title: preparado.title || null,
  source_url: preparado.source_url || null,
  source_name: preparado.source_name || null,
  language: preparado.language || null,
  chunks_count: Number.isFinite(chunksCount) ? chunksCount : null,
  document_id: body.document_id || body.id || (body.document && body.document.id) || null,
  http_status: httpStatus
};

if (httpStatus >= 400) {
  return registrarResultado({
    resultado: "error",
    ...base,
    chunks_count: null,
    document_id: null,
    mensaje: "La API respondio HTTP " + httpStatus + ".",
    api_body_preview: previewSeguro(body)
  });
}

if (apiStatus === "created") {
  return registrarResultado({
    resultado: "created",
    ...base,
    mensaje: "Documento creado correctamente."
  });
}

if (apiStatus === "verified_existing") {
  return registrarResultado({
    resultado: "verified_existing",
    ...base,
    mensaje: "El documento ya existia y fue verificado."
  });
}

if (apiStatus === "skipped") {
  return registrarResultado({
    resultado: "skipped",
    ...base,
    mensaje: body.message || body.detail || "La API omitio el documento."
  });
}

if (apiStatus === "rejected") {
  return registrarResultado({
    resultado: "rejected",
    ...base,
    mensaje: body.message || body.detail || "La API rechazo el documento."
  });
}

return registrarResultado({
  resultado: "error",
  ...base,
  chunks_count: null,
  document_id: null,
  mensaje: "La API respondio HTTP " + httpStatus + " pero no devolvio un status reconocible.",
  api_body_preview: previewSeguro(body)
});

const item = $json;

function registrarResultado(resultado) {
  const data = $getWorkflowStaticData("global");
  if (!Array.isArray(data.gospel_library_ingestion_results)) {
    data.gospel_library_ingestion_results = [];
  }
  data.gospel_library_ingestion_results.push(resultado);
  return [{ json: resultado }];
}

return registrarResultado({
  resultado: "skipped",
  title: item.title || null,
  source_url: item.source_url || null,
  source_name: item.source_name || null,
  language: item.language || null,
  chunks_count: null,
  document_id: null,
  mensaje: item.razon || "Documento omitido por validacion.",
  http_status: null
});

const data = $getWorkflowStaticData("global");
const resultados = Array.isArray(data.gospel_library_ingestion_results)
  ? data.gospel_library_ingestion_results
  : [];

const contador = {
  total_procesados: resultados.length,
  creados: 0,
  existentes: 0,
  omitidos: 0,
  rechazados: 0,
  errores: 0
};

const titulosCreados = [];
const urlsRechazadas = [];

for (const item of resultados) {
  if (item.resultado === "created") {
    contador.creados += 1;
    if (item.title) titulosCreados.push(item.title);
  } else if (item.resultado === "verified_existing") {
    contador.existentes += 1;
  } else if (item.resultado === "skipped") {
    contador.omitidos += 1;
  } else if (item.resultado === "rejected") {
    contador.rechazados += 1;
    urlsRechazadas.push({
      source_url: item.source_url || null,
      title: item.title || null,
      razon: item.mensaje || "Documento rechazado."
    });
  } else if (item.resultado === "error") {
    contador.errores += 1;
    urlsRechazadas.push({
      source_url: item.source_url || null,
      title: item.title || null,
      razon: item.mensaje || "Error durante la ingesta."
    });
  }
}

const mensaje = [
  "Procesados: " + contador.total_procesados,
  "creados: " + contador.creados,
  "existentes: " + contador.existentes,
  "omitidos: " + contador.omitidos,
  "rechazados: " + contador.rechazados,
  "errores: " + contador.errores
].join("; ");

return [{
  json: {
    resultado: "batch_summary",
    mensaje,
    started_at: data.gospel_library_ingestion_started_at || null,
    finished_at: new Date().toISOString(),
    ...contador,
    titulos_creados: titulosCreados,
    urls_rechazadas: urlsRechazadas,
    resultados
  }
}];
